const countries = [
  { name: 'Saudi Arabia', query: 'Saudi Arabia economy investment finance politics', code: 'SA' },
  { name: 'UAE',          query: 'UAE Dubai Abu Dhabi economy investment finance',  code: 'AE' },
  { name: 'Qatar',        query: 'Qatar economy investment finance LNG',            code: 'QA' },
  { name: 'Egypt',        query: 'Egypt economy investment finance IMF',            code: 'EG' },
  { name: 'Kuwait',       query: 'Kuwait economy investment finance oil',           code: 'KW' }
];
return countries.map(c => ({ json: c }));

const countryItems = $('Country List').all();
const currentIndex = $('Fetch News (NewsAPI)').context?.currentRunIndex || 0;
const country = countryItems[currentIndex]?.json || countryItems[0].json;

const articles = $input.first().json.articles || [];

const headlines = articles
  .slice(0, 20)
  .map((a, i) => `${i+1}. [${a.source?.name || 'Unknown'}] ${a.title} — ${(a.description || '').slice(0, 120)}`)
  .join('\n');

return [{
  json: {
    country: $('Country List').item.json.name,
    code: $('Country List').item.json.code,
    date: new Date().toISOString().split('T')[0],
    headlines: headlines || 'No articles found for today.',
    articleCount: articles.length
  }
}];

