  },
  "risk_direction": "improving or stable or deteriorating",
  "executive_briefing": "3-4 sentence summary of key developments and IB implications",
  "regulatory_updates": [
    { "title": "string", "impact": "positive or neutral or negative", "detail": "string" }
  ],
  "deal_opportunities": [
    { "type": "M&A or IPO or Project Finance or Capital Markets", "description": "string", "urgency": "high or medium or low" }
  ],
  "alerts": [
    { "severity": "critical or high or medium", "message": "string" }
  ]
}"
    }]
  }],
  "generationConfig": {
    "temperature": 0.3,
    "maxOutputTokens": 1500
  }
}

parameters.jsCode:
const raw = $input.first().json;

let text = '';
try {
  text = raw.candidates[0].content.parts[0].text;
} catch(e) {
  return [{ json: { error: 'Gemini response parse failed', raw: JSON.stringify(raw) } }];
}

let analysis;
try {
  const cleaned = text.replace(/```json/g, '').replace(/```/g, '').trim();
  analysis = JSON.parse(cleaned);
} catch(e) {
  const match = text.match(/\{[\s\S]*\}/);
  try {
    analysis = match ? JSON.parse(match[0]) : { error: 'JSON parse failed', raw: text };
  } catch(e2) {
    analysis = { error: 'JSON parse failed', raw: text };
  }
}

const prevData = $('Prepare Headlines').first().json;
return [{ json: { ...prevData, analysis } }];

const d = $input.first().json;
const a = d.analysis;

if (a.error) {
  return [{ json: { ...d, html_email: `<p>Analysis error for ${d.country}: ${a.error}</p>`, is_high_risk: false, has_critical_alert: false } }];
}

const score = a.overall_risk_score || 0;
const isHighRisk = score > 65;
const hasCriticalAlert = (a.alerts || []).some(x => x.severity === 'critical');
const directionArrow = a.risk_direction === 'improving' ? '↓' : a.risk_direction === 'deteriorating' ? '↑' : '→';
const directionColor = a.risk_direction === 'improving' ? '#27500A' : a.risk_direction === 'deteriorating' ? '#791F1F' : '#5F5E5A';
const scoreColor = score < 35 ? '#27500A' : score < 65 ? '#633806' : '#791F1F';
const scoreBg    = score < 35 ? '#EAF3DE'  : score < 65 ? '#FAEEDA'  : '#FCEBEB';

const regulatoryHtml = (a.regulatory_updates || []).map(r => {
  const dot = r.impact === 'positive' ? '#639922' : r.impact === 'negative' ? '#E24B4A' : '#888780';
  return `<tr><td style="padding:8px 0;border-bottom:1px solid #f0f0f0;vertical-align:top">
    <span style="display:inline-block;width:8px;height:8px;border-radius:50%;background:${dot};margin-right:8px;margin-top:4px;float:left"></span>
    <span style="font-size:13px;color:#1a1a1a">${r.title}</span><br>
    <span style="font-size:12px;color:#666">${r.detail}</span>
  </td></tr>`;
}).join('');

const dealsHtml = (a.deal_opportunities || []).map(op => {
  const urgColor = op.urgency === 'high' ? '#791F1F' : op.urgency === 'medium' ? '#633806' : '#27500A';
  const urgBg    = op.urgency === 'high' ? '#FCEBEB' : op.urgency === 'medium' ? '#FAEEDA' : '#EAF3DE';
  return `<tr><td style="padding:8px 0;border-bottom:1px solid #f0f0f0">
    <span style="font-size:10px;font-weight:600;padding:2px 8px;border-radius:99px;background:${urgBg};color:${urgColor};margin-right:8px">${(op.urgency||'').toUpperCase()}</span>
    <span style="font-size:11px;color:#888;margin-right:6px">${op.type}</span>
    <span style="font-size:13px;color:#1a1a1a">${op.description}</span>
  </td></tr>`;
}).join('');

const alertsHtml = (a.alerts || []).filter(x => x.severity === 'critical' || x.severity === 'high').map(al => {
  const bg  = al.severity === 'critical' ? '#FCEBEB' : '#FAEEDA';
  const col = al.severity === 'critical' ? '#791F1F' : '#633806';
  return `<div style="background:${bg};border-left:3px solid ${col};padding:10px 14px;margin-bottom:8px;border-radius:0 6px 6px 0">
    <span style="font-size:11px;font-weight:600;color:${col}">${al.severity.toUpperCase()} ALERT</span><br>
    <span style="font-size:13px;color:#1a1a1a">${al.message}</span>
  </div>`;
}).join('');

const dims = a.risk_dimensions || {};
const dimRows = Object.entries(dims).map(([k, v]) => {
  const label = k.replace(/_/g, ' ');
  const bar = Math.round(Number(v) || 0);
  const bCol = bar < 35 ? '#639922' : bar < 65 ? '#EF9F27' : '#E24B4A';
  return `<tr>
    <td style="font-size:12px;color:#666;padding:5px 0;width:140px;text-transform:capitalize">${label}</td>
    <td style="padding:5px 8px"><div style="background:#f0f0f0;border-radius:99px;height:6px;width:100%"><div style="background:${bCol};width:${bar}%;height:6px;border-radius:99px"></div></div></td>
    <td style="font-size:12px;font-weight:500;color:#1a1a1a;text-align:right;padding:5px 0;width:30px">${bar}</td>
  </tr>`;
}).join('');

const html = `<!DOCTYPE html><html><body style="margin:0;padding:0;background:#f5f5f0;font-family:-apple-system,BlinkMacSystemFont,'Segoe UI',sans-serif">
<div style="max-width:620px;margin:0 auto;padding:24px 16px">
  <div style="background:#042C53;border-radius:10px 10px 0 0;padding:20px 24px">
    <p style="margin:0;font-size:11px;color:#85B7EB;letter-spacing:.08em">INVESTMENT BANKING INTELLIGENCE</p>
    <h1 style="margin:6px 0 0;font-size:22px;font-weight:500;color:#fff">${a.country || d.country}</h1>
    <p style="margin:4px 0 0;font-size:12px;color:#85B7EB">${a.date || d.date} · Automated daily briefing · Powered by Gemini AI</p>
  </div>
  <div style="background:#fff;padding:20px 24px;border-left:1px solid #e8e8e8;border-right:1px solid #e8e8e8">
    <table style="width:100%;margin-bottom:20px"><tr>
      <td style="text-align:center">
        <div style="display:inline-flex;width:64px;height:64px;border-radius:50%;background:${scoreBg};align-items:center;justify-content:center">
          <span style="font-size:22px;font-weight:500;color:${scoreColor}">${Math.round(score)}</span>
        </div>
        <div style="font-size:11px;color:#888;margin-top:4px">Risk score</div>
      </td>
      <td style="text-align:center">
        <div style="font-size:24px;color:${directionColor}">${directionArrow}</div>
        <div style="font-size:11px;color:#888;margin-top:4px;text-transform:capitalize">${a.risk_direction || 'stable'}</div>
      </td>
      <td style="text-align:center">
        <div style="font-size:20px;font-weight:500;color:#1a1a1a">${(a.deal_opportunities || []).length}</div>
        <div style="font-size:11px;color:#888;margin-top:4px">Deal signals</div>
      </td>
      <td style="text-align:center">
        <div style="font-size:20px;font-weight:500;color:${hasCriticalAlert ? '#791F1F' : '#1a1a1a'}">${(a.alerts || []).length}</div>
        <div style="font-size:11px;color:#888;margin-top:4px">Alerts</div>
      </td>
    </tr></table>
    ${alertsHtml ? `<div style="margin-bottom:20px">${alertsHtml}</div>` : ''}
    <div style="margin-bottom:20px">
      <p style="font-size:11px;font-weight:600;color:#888;letter-spacing:.06em;margin:0 0 8px">EXECUTIVE BRIEFING</p>
      <p style="font-size:14px;color:#1a1a1a;line-height:1.7;margin:0">${a.executive_briefing || 'No briefing generated.'}</p>
    </div>
    <div style="margin-bottom:20px">
      <p style="font-size:11px;font-weight:600;color:#888;letter-spacing:.06em;margin:0 0 8px">RISK DIMENSIONS</p>
      <table style="width:100%">${dimRows}</table>
    </div>
    ${regulatoryHtml ? `<div style="margin-bottom:20px"><p style="font-size:11px;font-weight:600;color:#888;letter-spacing:.06em;margin:0 0 8px">REGULATORY UPDATES</p><table style="width:100%">${regulatoryHtml}</table></div>` : ''}
    ${dealsHtml ? `<div style="margin-bottom:8px"><p style="font-size:11px;font-weight:600;color:#888;letter-spacing:.06em;margin:0 0 8px">DEAL OPPORTUNITIES</p><table style="width:100%">${dealsHtml}</table></div>` : ''}
  </div>
  <div style="background:#f0ede8;border-radius:0 0 10px 10px;padding:14px 24px;border:1px solid #e8e8e8;border-top:none">
    <p style="margin:0;font-size:11px;color:#888">Automated by Gemini AI + n8n · ${d.articleCount} articles processed · Internal use only</p>
  </div>
</div>
</body></html>`;

return [{ json: { ...d, html_email: html, is_high_risk: isHighRisk, has_critical_alert: hasCriticalAlert } }];

